// Clean and normalize SKUs
// Rules: uppercase, trim whitespace, remove special characters

const items = $input.all();
const results = [];

for (const item of items) {
  const data = { ...item.json };

  // Clean SKU
  if (data.sku) {
    data.sku = data.sku
      .toString()
      .trim()
      .toUpperCase()
      .replace(/[^A-Z0-9_-]/g, ''); // Remove invalid characters
  }

  // Clean product name
  if (data.product_name) {
    data.product_name = data.product_name
      .toString()
      .trim()
      .replace(/\s+/g, ' '); // Normalize whitespace
  }

  results.push({ json: data });
}

return results;

// Validate and clean URLs
// Ensure all URLs are accessible and properly formatted

const items = $input.all();
const results = [];

function isValidUrl(url) {
  try {
    const urlObj = new URL(url);
    return urlObj.protocol === 'http:' || urlObj.protocol === 'https:';
  } catch (e) {
    return false;
  }
}

function cleanUrl(url) {
  return url.toString().trim();
}

for (const item of items) {
  const data = { ...item.json };

  // Clean and validate image URLs
  if (data.image_urls && Array.isArray(data.image_urls)) {
    data.image_urls = data.image_urls
      .map(img => {
        if (typeof img === 'string') {
          return { url: cleanUrl(img), type: 'image' };
        }
        return { ...img, url: cleanUrl(img.url) };
      })
      .filter(img => isValidUrl(img.url));
  } else {
    data.image_urls = [];
  }

  // Clean and validate video URLs
  if (data.video_urls && Array.isArray(data.video_urls)) {
    data.video_urls = data.video_urls
      .map(vid => {
        if (typeof vid === 'string') {
          return { url: cleanUrl(vid), type: 'video' };
        }
        return { ...vid, url: cleanUrl(vid.url) };
      })
      .filter(vid => isValidUrl(vid.url));
  } else {
    data.video_urls = [];
  }

  // Clean document URLs
  if (data.document_urls && Array.isArray(data.document_urls)) {
    data.document_urls = data.document_urls
      .map(doc => {
        if (typeof doc === 'string') {
          return { url: cleanUrl(doc), type: 'document' };
        }
        return { ...doc, url: cleanUrl(doc.url) };
      })
      .filter(doc => isValidUrl(doc.url));
  } else {
    data.document_urls = [];
  }

  results.push({ json: data });
}

return results;

// Clean text fields
// Remove HTML tags, limit character count, normalize whitespace

const items = $input.all();
const results = [];

function cleanText(text, maxLength = 5000) {
  if (!text) return '';

  // Convert to string
  let cleaned = text.toString();

  // Remove HTML tags
  cleaned = cleaned.replace(/<[^>]*>/g, '');

  // Decode HTML entities
  cleaned = cleaned
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

  // Normalize whitespace
  cleaned = cleaned.replace(/\s+/g, ' ').trim();

  // Limit length
  if (cleaned.length > maxLength) {
    cleaned = cleaned.substring(0, maxLength) + '...';
  }

  return cleaned;
}

for (const item of items) {
  const data = { ...item.json };

  // Clean product name
  if (data.product_name) {
    data.product_name = cleanText(data.product_name, 200);
  }

  // Clean marketing copy
  if (data.marketing_copy) {
    data.marketing_copy = cleanText(data.marketing_copy, 5000);
  }

  results.push({ json: data });
}

return results;

// Add metadata and standardize structure
// Ensure all required fields are present

const items = $input.all();
const results = [];

for (const item of items) {
  const data = { ...item.json };

  // Ensure required fields exist
  if (!data.sku) {
    continue; // Skip items without SKU
  }

  // Set defaults for missing fields
  data.product_name = data.product_name || '';
  data.image_urls = data.image_urls || [];
  data.video_urls = data.video_urls || [];
  data.marketing_copy = data.marketing_copy || '';
  data.source_tier = data.source_tier || 1;
  data.last_updated = new Date().toISOString();

  // Ensure metadata exists
  if (!data.metadata) {
    data.metadata = {};
  }

  // Add standard metadata
  data.metadata = {
    ...data.metadata,
    source_tier: 1,
    last_updated: data.last_updated,
    total_images: data.image_urls.length,
    total_videos: data.video_urls.length,
    has_marketing_copy: data.marketing_copy.length > 0,
    data_quality_score: calculateQualityScore(data)
  };

  results.push({ json: data });
}

function calculateQualityScore(data) {
  let score = 0;

  // SKU present (required)
  if (data.sku) score += 20;

  // Product name present
  if (data.product_name && data.product_name.length > 0) score += 20;

  // Has images
  if (data.image_urls && data.image_urls.length > 0) score += 30;

  // Has videos
  if (data.video_urls && data.video_urls.length > 0) score += 15;

  // Has marketing copy
  if (data.marketing_copy && data.marketing_copy.length > 50) score += 15;

  return score;
}

return results;
